import{c as p,a7 as r,y as e,B as D}from"./chunks/framework.3cjvm90C.js";const h=JSON.parse('{"title":"Spark 简介 (Python 版)","description":"Apache Spark 的基本概念与 Python 接口入门","frontmatter":{"title":"Spark 简介 (Python 版)","description":"Apache Spark 的基本概念与 Python 接口入门"},"headers":[],"relativePath":"mlwiki/Spark/spark_intro.md","filePath":"mlwiki/Spark/spark_intro.md","lastUpdated":1782456021000}'),o={name:"mlwiki/Spark/spark_intro.md"};function i(s,a,t,n,l,k){return r(),e("div",null,[...a[0]||(a[0]=[D(`<h1 id="spark-简介-python-版" tabindex="-1">Spark 简介(Python 版) <a class="header-anchor" href="#spark-简介-python-版" aria-label="Permalink to “Spark 简介(Python 版)”">​</a></h1><h2 id="关于-spark" tabindex="-1">关于 Spark <a class="header-anchor" href="#关于-spark" aria-label="Permalink to “关于 Spark”">​</a></h2><p>Spark 最初由美国加州伯克利大学（UCBerkeley）的 AMP（Algorithms, Machines and People）实验室于 2009 年开发，是基于内存计算的大数据并行计算框架，可用于构建大型的、低延迟的数据分析应用程序。Spark 在诞生之初属于研究性项目，其诸多核心理念均源自学术研究论文。2013 年，Spark 加入 Apache 孵化器项目后，开始获得迅猛的发展，如今已成为 Apache 软件基金会最重要的三大分布式计算系统开源项目之一（即 Hadoop、Spark、Storm）。</p><p>Spark 作为大数据计算平台的后起之秀，在 2014 年打破了 Hadoop 保持的基准排序（Sort Benchmark）纪录，使用 206 个节点在 23 分钟的时间里完成了 100TB 数据的排序，而 Hadoop 则是使用 2000 个节点在 72 分钟的时间里完成同样数据的排序。也就是说，Spark 仅使用了十分之一的计算资源，获得了比 Hadoop 快 3 倍的速度。新纪录的诞生，使得 Spark 获得多方追捧，也表明了 Spark 可以作为一个更加快速、高效的大数据计算平台。 Spark 具有如下几个主要特点：  运行速度快：Spark 使用先进的 DAG（Directed Acyclic Graph，有向无环图）执行引擎，以支持循环数据流与内存计算，基于内存的执行速度可比 Hadoop MapReduce 快上百倍，基于磁盘的执行速度也能快十倍；  容易使用：Spark 支持使用 Scala、Java、Python 和 R 语言进行编程，简洁的 API 设计有助于用户轻松构建并行程序，并且可以通过 Spark Shell 进行交互式编程；  通用性：Spark 提供了完整而强大的技术栈，包括 SQL 查询、流式计算、机器学习和图算法组件，这些组件可以无缝整合在同一个应用中，足以应对复杂的计算；  运行模式多样：Spark 可运行于独立的集群模式中，或者运行于 Hadoop 中，也可运行于 Amazon EC2 等云环境中，并且可以访问 HDFS、Cassandra、HBase、Hive 等多种数据源。 Spark 源码托管在 Github 中，截至 2016 年 3 月，共有超过 800 名来自 200 多家不同公司的开发人员贡献了 15000 次代码提交，可见 Spark 的受欢迎程度。</p><p>此外，每年举办的全球 Spark 顶尖技术人员峰会 Spark Summit，吸引了使用 Spark 的一线技术公司及专家汇聚一堂，共同探讨目前 Spark 在企业的落地情况及未来 Spark 的发展方向和挑战。Spark Summit 的参会人数从 2014 年的不到 500 人暴涨到 2015 年的 2000 多人，足以反映 Spark 社区的旺盛人气。 Spark 如今已吸引了国内外各大公司的注意，如腾讯、淘宝、百度、亚马逊等公司均不同程度地使用了 Spark 来构建大数据分析应用，并应用到实际的生产环境中。相信在将来，Spark 会在更多的应用场景中发挥重要作用。</p><h2 id="spark-相对于-hadoop-的优势" tabindex="-1">Spark 相对于 Hadoop 的优势 <a class="header-anchor" href="#spark-相对于-hadoop-的优势" aria-label="Permalink to “Spark 相对于 Hadoop 的优势”">​</a></h2><p>Hadoop 虽然已成为大数据技术的事实标准，但其本身还存在诸多缺陷，最主要的缺陷是其 MapReduce 计算模型延迟过高，无法胜任实时、快速计算的需求，因而只适用于离线批处理的应用场景。 回顾 Hadoop 的工作流程，可以发现 Hadoop 存在如下一些缺点：  表达能力有限。计算都必须要转化成 Map 和 Reduce 两个操作，但这并不适合所有的情况，难以描述复杂的数据处理过程；  磁盘 IO 开销大。每次执行时都需要从磁盘读取数据，并且在计算完成后需要将中间结果写入到磁盘中，IO 开销较大；  延迟高。一次计算可能需要分解成一系列按顺序执行的 MapReduce 任务，任务之间的衔接由于涉及到 IO 开销，会产生较高延迟。而且，在前一个任务执行完成之前，其他任务无法开始，难以胜任复杂、多阶段的计算任务。 Spark 在借鉴 Hadoop MapReduce 优点的同时，很好地解决了 MapReduce 所面临的问题。相比于 MapReduce，Spark 主要具有如下优点：  Spark 的计算模式也属于 MapReduce，但不局限于 Map 和 Reduce 操作，还提供了多种数据集操作类型，编程模型比 MapReduce 更灵活；  Spark 提供了内存计算，中间结果直接放到内存中，带来了更高的迭代运算效率；  Spark 基于 DAG 的任务调度执行机制，要优于 MapReduce 的迭代执行机制。</p><p>Spark 最大的特点就是将计算数据、中间结果都存储在内存中，大大减少了 IO 开销，因而，Spark 更适合于迭代运算比较多的数据挖掘与机器学习运算。使用 Hadoop 进行迭代计算非常耗资源，因为每次迭代都需要从磁盘中写入、读取中间数据，IO 开销大。而 Spark 将数据载入内存后，之后的迭代计算都可以直接使用内存中的中间结果作运算，避免了从磁盘中频繁读取数据。</p><p>在实际进行开发时，使用 Hadoop 需要编写不少相对底层的代码，不够高效。相对而言，Spark 提供了多种高层次、简洁的 API，通常情况下，对于实现相同功能的应用程序，Spark 的代码量要比 Hadoop 少 2-5 倍。更重要的是，Spark 提供了实时交互式编程反馈，可以方便地验证、调整算法。 尽管 Spark 相对于 Hadoop 而言具有较大优势，但 Spark 并不能完全替代 Hadoop，主要用于替代 Hadoop 中的 MapReduce 计算模型。实际上，Spark 已经很好地融入了 Hadoop 生态圈，并成为其中的重要一员，它可以借助于 YARN 实现资源调度管理，借助于 HDFS 实现分布式存储。此外，Hadoop 可以使用廉价的、异构的机器来做分布式存储与计算，但是，Spark 对硬件的要求稍高一些，对内存与 CPU 有一定的要求。</p><h2 id="spark-生态系统" tabindex="-1">Spark 生态系统 <a class="header-anchor" href="#spark-生态系统" aria-label="Permalink to “Spark 生态系统”">​</a></h2><p>在实际应用中，大数据处理主要包括以下三个类型：  复杂的批量数据处理：时间跨度通常在数十分钟到数小时之间；  基于历史数据的交互式查询：时间跨度通常在数十秒到数分钟之间；  基于实时数据流的数据处理：时间跨度通常在数百毫秒到数秒之间。 目前已有很多相对成熟的开源软件用于处理以上三种情景，比如，可以利用 Hadoop MapReduce 来进行批量数据处理，可以用 Impala 来进行交互式查询（Impala 与 Hive 相似，但底层引擎不同，提供了实时交互式 SQL 查询），对于流式数据处理可以采用开源流计算框架 Storm。一些企业可能只会涉及其中部分应用场景，只需部署相应软件即可满足业务需求，但是，对于互联网公司而言，通常会同时存在以上三种场景，就需要同时部署三种不同的软件，这样做难免会带来一些问题：  不同场景之间输入输出数据无法做到无缝共享，通常需要进行数据格式的转换；  不同的软件需要不同的开发和维护团队，带来了较高的使用成本；  比较难以对同一个集群中的各个系统进行统一的资源协调和分配。 Spark 的设计遵循“一个软件栈满足不同应用场景”的理念，逐渐形成了一套完整的生态系统，既能够提供内存计算框架，也可以支持 SQL 即席查询、实时流式计算、机器学习和图计算等。Spark 可以部署在资源管理器 YARN 之上，提供一站式的大数据解决方案。因此，Spark 所提供的生态系统足以应对上述三种场景，即同时支持批处理、交互式查询和流数据处理。 现在，Spark 生态系统已经成为伯克利数据分析软件栈 BDAS（Berkeley Data Analytics Stack）的重要组成部分。BDAS 的架构如图所示，从中可以看出，Spark 专注于数据的处理分析，而数据的存储还是要借助于 Hadoop 分布式文件系统 HDFS、Amazon S3 等来实现的。因此，Spark 生态系统可以很好地实现与 Hadoop 生态系统的兼容，使得现有 Hadoop 应用程序可以非常容易地迁移到 Spark 系统中。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/10/%E5%9B%BE-BDAS%E6%9E%B6%E6%9E%84.jpg" alt="img"> 图 BDAS 架构 Spark 的生态系统主要包含了 Spark Core、Spark SQL、Spark Streaming、MLLib 和 GraphX 等组件，各个组件的具体功能如下： *  Spark Core：Spark Core 包含 Spark 的基本功能，如内存计算、任务调度、部署模式、故障恢复、存储管理等。Spark 建立在统一的抽象 RDD 之上，使其可以以基本一致的方式应对不同的大数据处理场景；通常所说的 Apache Spark，就是指 Spark Core； *  Spark SQL：Spark SQL 允许开发人员直接处理 RDD，同时也可查询 Hive、HBase 等外部数据源。Spark SQL 的一个重要特点是其能够统一处理关系表和 RDD，使得开发人员可以轻松地使用 SQL 命令进行查询，并进行更复杂的数据分析； *  Spark Streaming：Spark Streaming 支持高吞吐量、可容错处理的实时流数据处理，其核心思路是将流式计算分解成一系列短小的批处理作业。Spark Streaming 支持多种数据输入源，如 Kafka、Flume 和 TCP 套接字等； *  MLlib（机器学习）：MLlib 提供了常用机器学习算法的实现，包括聚类、分类、回归、协同过滤等，降低了机器学习的门槛，开发人员只要具备一定的理论知识就能进行机器学习的工作； *  GraphX（图计算）：GraphX 是 Spark 中用于图计算的 API，可认为是 Pregel 在 Spark 上的重写及优化，Graphx 性能良好，拥有丰富的功能和运算符，能在海量数据上自如地运行复杂的图算法。</p><h1 id="spark-运行架构-python-版" tabindex="-1">Spark 运行架构(Python 版) <a class="header-anchor" href="#spark-运行架构-python-版" aria-label="Permalink to “Spark 运行架构(Python 版)”">​</a></h1><p>本节首先介绍 Spark 的基本概念和架构设计方法，然后介绍 Spark 运行基本流程。</p><h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to “基本概念”">​</a></h2><p>在具体讲解 Spark 运行架构之前，需要先了解几个重要的概念：</p><ul><li>RDD：是弹性分布式数据集（Resilient Distributed Dataset）的简称，是分布式内存的一个抽象概念，提供了一种高度受限的共享内存模型；</li><li>DAG：是 Directed Acyclic Graph（有向无环图）的简称，反映 RDD 之间的依赖关系；</li><li>Executor：是运行在工作节点（Worker Node）上的一个进程，负责运行任务，并为应用程序存储数据；</li><li>应用：用户编写的 Spark 应用程序；</li><li>任务：运行在 Executor 上的工作单元；</li><li>作业：一个作业包含多个 RDD 及作用于相应 RDD 上的各种操作；</li><li>阶段：是作业的基本调度单位，一个作业会分为多组任务，每组任务被称为“阶段”，或者也被称为“任务集”。</li></ul><h2 id="架构设计" tabindex="-1">架构设计 <a class="header-anchor" href="#架构设计" aria-label="Permalink to “架构设计”">​</a></h2><p>如图 9-5 所示，Spark 运行架构包括集群资源管理器（Cluster Manager）、运行作业任务的工作节点（Worker Node）、每个应用的任务控制节点（Driver）和每个工作节点上负责具体任务的执行进程（Executor）。其中，集群资源管理器可以是 Spark 自带的资源管理器，也可以是 YARN 或 Mesos 等资源管理框架。 与 Hadoop MapReduce 计算框架相比，Spark 所采用的 Executor 有两个优点：一是利用多线程来执行具体的任务（Hadoop MapReduce 采用的是进程模型），减少任务的启动开销；二是 Executor 中有一个 BlockManager 存储模块，会将内存和磁盘共同作为存储设备，当需要多轮迭代计算时，可以将中间结果存储到这个存储模块里，下次需要时，就可以直接读该存储模块里的数据，而不需要读写到 HDFS 等文件系统里，因而有效减少了 IO 开销；或者在交互式查询场景下，预先将表缓存到该存储系统上，从而可以提高读写 IO 性能。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-5-Spark%E8%BF%90%E8%A1%8C%E6%9E%B6%E6%9E%84.jpg" alt="img"></p><p>​ 图 9-5 Spark 运行架构</p><p>总体而言，如图 9-6 所示，在 Spark 中，一个应用（Application）由一个任务控制节点（Driver）和若干个作业（Job）构成，一个作业由多个阶段（Stage）构成，一个阶段由多个任务（Task）组成。当执行一个应用时，任务控制节点会向集群管理器（Cluster Manager）申请资源，启动 Executor，并向 Executor 发送应用程序代码和文件，然后在 Executor 上执行任务，运行结束后，执行结果会返回给任务控制节点，或者写到 HDFS 或者其他数据库中。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-6-Spark%E4%B8%AD%E5%90%84%E7%A7%8D%E6%A6%82%E5%BF%B5%E4%B9%8B%E9%97%B4%E7%9A%84%E7%9B%B8%E4%BA%92%E5%85%B3%E7%B3%BB.jpg" alt="img"></p><p>图 9-6 Spark 中各种概念之间的相互关系</p><h2 id="spark-运行基本流程" tabindex="-1">Spark 运行基本流程 <a class="header-anchor" href="#spark-运行基本流程" aria-label="Permalink to “Spark 运行基本流程”">​</a></h2><p>如图 9-7 所示，Spark 的基本运行流程如下： （1）当一个 Spark 应用被提交时，首先需要为这个应用构建起基本的运行环境，即由任务控制节点（Driver）创建一个 SparkContext，由 SparkContext 负责和资源管理器（Cluster Manager）的通信以及进行资源的申请、任务的分配和监控等。SparkContext 会向资源管理器注册并申请运行 Executor 的资源； （2）资源管理器为 Executor 分配资源，并启动 Executor 进程，Executor 运行情况将随着“心跳”发送到资源管理器上； （3）SparkContext 根据 RDD 的依赖关系构建 DAG 图，DAG 图提交给 DAG 调度器（DAGScheduler）进行解析，将 DAG 图分解成多个“阶段”（每个阶段都是一个任务集），并且计算出各个阶段之间的依赖关系，然后把一个个“任务集”提交给底层的任务调度器（TaskScheduler）进行处理；Executor 向 SparkContext 申请任务，任务调度器将任务分发给 Executor 运行，同时，SparkContext 将应用程序代码发放给 Executor； （4）任务在 Executor 上运行，把执行结果反馈给任务调度器，然后反馈给 DAG 调度器，运行完毕后写入数据并释放所有资源。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-7-Spark%E8%BF%90%E8%A1%8C%E5%9F%BA%E6%9C%AC%E6%B5%81%E7%A8%8B%E5%9B%BE.jpg" alt="img"> 图 9-7 Spark 运行基本流程图</p><p>总体而言，Spark 运行架构具有以下特点： （1）每个应用都有自己专属的 Executor 进程，并且该进程在应用运行期间一直驻留。Executor 进程以多线程的方式运行任务，减少了多进程任务频繁的启动开销，使得任务执行变得非常高效和可靠； （2）Spark 运行过程与资源管理器无关，只要能够获取 Executor 进程并保持通信即可； （3）Executor 上有一个 BlockManager 存储模块，类似于键值存储系统（把内存和磁盘共同作为存储设备），在处理迭代计算任务时，不需要把中间结果写入到 HDFS 等文件系统，而是直接放在这个存储系统上，后续有需要时就可以直接读取；在交互式查询场景下，也可以把表提前缓存到这个存储系统上，提高读写 IO 性能； （4）任务采用了数据本地性和推测执行等优化机制。数据本地性是尽量将计算移到数据所在的节点上进行，即“计算向数据靠拢”，因为移动计算比移动数据所占的网络资源要少得多。而且，Spark 采用了延时调度机制，可以在更大的程度上实现执行过程优化。比如，拥有数据的节点当前正被其他的任务占用，那么，在这种情况下是否需要将数据移动到其他的空闲节点呢？答案是不一定。因为，如果经过预测发现当前节点结束当前任务的时间要比移动数据的时间还要少，那么，调度就会等待，直到当前节点可用。</p><h1 id="rdd-的设计与运行原理-python-版" tabindex="-1">RDD 的设计与运行原理(Python 版) <a class="header-anchor" href="#rdd-的设计与运行原理-python-版" aria-label="Permalink to “RDD 的设计与运行原理(Python 版)”">​</a></h1><p>Spark 的核心是建立在统一的抽象 RDD 之上，使得 Spark 的各个组件可以无缝进行集成，在同一个应用程序中完成大数据计算任务。RDD 的设计理念源自 AMP 实验室发表的论文《Resilient Distributed Datasets: A Fault-Tolerant Abstraction for In-Memory Cluster Computing》。</p><h2 id="_1-rdd-设计背景" tabindex="-1">1.RDD 设计背景 <a class="header-anchor" href="#_1-rdd-设计背景" aria-label="Permalink to “1.RDD 设计背景”">​</a></h2><p>在实际应用中，存在许多迭代式算法（比如机器学习、图算法等）和交互式数据挖掘工具，这些应用场景的共同之处是，不同计算阶段之间会重用中间结果，即一个阶段的输出结果会作为下一个阶段的输入。但是，目前的 MapReduce 框架都是把中间结果写入到 HDFS 中，带来了大量的数据复制、磁盘 IO 和序列化开销。虽然，类似 Pregel 等图计算框架也是将结果保存在内存当中，但是，这些框架只能支持一些特定的计算模式，并没有提供一种通用的数据抽象。RDD 就是为了满足这种需求而出现的，它提供了一个抽象的数据架构，我们不必担心底层数据的分布式特性，只需将具体的应用逻辑表达为一系列转换处理，不同 RDD 之间的转换操作形成依赖关系，可以实现管道化，从而避免了中间结果的存储，大大降低了数据复制、磁盘 IO 和序列化开销。</p><h2 id="_2-rdd-概念" tabindex="-1">2.RDD 概念 <a class="header-anchor" href="#_2-rdd-概念" aria-label="Permalink to “2.RDD 概念”">​</a></h2><p>一个 RDD 就是一个分布式对象集合，本质上是一个只读的分区记录集合，每个 RDD 可以分成多个分区，每个分区就是一个数据集片段，并且一个 RDD 的不同分区可以被保存到集群中不同的节点上，从而可以在集群中的不同节点上进行并行计算。RDD 提供了一种高度受限的共享内存模型，即 RDD 是只读的记录分区的集合，不能直接修改，只能基于稳定的物理存储中的数据集来创建 RDD，或者通过在其他 RDD 上执行确定的转换操作（如 map、join 和 groupBy）而创建得到新的 RDD。RDD 提供了一组丰富的操作以支持常见的数据运算，分为“行动”（Action）和“转换”（Transformation）两种类型，前者用于执行计算并指定输出的形式，后者指定 RDD 之间的相互依赖关系。两类操作的主要区别是，转换操作（比如 map、filter、groupBy、join 等）接受 RDD 并返回 RDD，而行动操作（比如 count、collect 等）接受 RDD 但是返回非 RDD（即输出一个值或结果）。RDD 提供的转换接口都非常简单，都是类似 map、filter、groupBy、join 等粗粒度的数据转换操作，而不是针对某个数据项的细粒度修改。因此，RDD 比较适合对于数据集中元素执行相同操作的批处理式应用，而不适合用于需要异步、细粒度状态的应用，比如 Web 应用系统、增量式的网页爬虫等。正因为这样，这种粗粒度转换接口设计，会使人直觉上认为 RDD 的功能很受限、不够强大。但是，实际上 RDD 已经被实践证明可以很好地应用于许多并行计算应用中，可以具备很多现有计算框架（比如 MapReduce、SQL、Pregel 等）的表达能力，并且可以应用于这些框架处理不了的交互式数据挖掘应用。 Spark 用 Scala 语言实现了 RDD 的 API，程序员可以通过调用 API 实现对 RDD 的各种操作。RDD 典型的执行过程如下：</p><ol><li>RDD 读入外部数据源（或者内存中的集合）进行创建；</li><li>RDD 经过一系列的“转换”操作，每一次都会产生不同的 RDD，供给下一个“转换”使用；</li><li>最后一个 RDD 经“行动”操作进行处理，并输出到外部数据源（或者变成 Scala 集合或标量）。</li></ol><p>需要说明的是，RDD 采用了惰性调用，即在 RDD 的执行过程中（如图 9-8 所示），真正的计算发生在 RDD 的“行动”操作，对于“行动”之前的所有“转换”操作，Spark 只是记录下“转换”操作应用的一些基础数据集以及 RDD 生成的轨迹，即相互之间的依赖关系，而不会触发真正的计算。 <img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-8-Spark%E7%9A%84%E8%BD%AC%E6%8D%A2%E5%92%8C%E8%A1%8C%E5%8A%A8%E6%93%8D%E4%BD%9C.jpg" alt="图 9-8 Spark 的转换和行动操作"> 图 9-8 Spark 的转换和行动操作例如，在图 9-9 中，从输入中逻辑上生成 A 和 C 两个 RDD，经过一系列“转换”操作，逻辑上生成了 F（也是一个 RDD），之所以说是逻辑上，是因为这时候计算并没有发生，Spark 只是记录了 RDD 之间的生成和依赖关系。当 F 要进行输出时，也就是当 F 进行“行动”操作的时候，Spark 才会根据 RDD 的依赖关系生成 DAG，并从起点开始真正的计算。 <img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-9-RDD%E6%89%A7%E8%A1%8C%E8%BF%87%E7%A8%8B%E7%9A%84%E4%B8%80%E4%B8%AA%E5%AE%9E%E4%BE%8B.jpg" alt="图 9-9 RDD 执行过程的一个实例"> 图 9-9 RDD 执行过程的一个实例上述这一系列处理称为一个“血缘关系（Lineage）”，即 DAG 拓扑排序的结果。采用惰性调用，通过血缘关系连接起来的一系列 RDD 操作就可以实现管道化（pipeline），避免了多次转换操作之间数据同步的等待，而且不用担心有过多的中间数据，因为这些具有血缘关系的操作都管道化了，一个操作得到的结果不需要保存为中间数据，而是直接管道式地流入到下一个操作进行处理。同时，这种通过血缘关系把一系列操作进行管道化连接的设计方式，也使得管道中每次操作的计算变得相对简单，保证了每个操作在处理逻辑上的单一性；相反，在 MapReduce 的设计中，为了尽可能地减少 MapReduce 过程，在单个 MapReduce 中会写入过多复杂的逻辑。 例 1：一个 Spark 的“Hello World”程序这里以一个“Hello World”入门级 Spark 程序来解释 RDD 执行过程，这个程序的功能是读取一个 HDFS 文件，计算出包含字符串“Hello World”的行数。</p><p>启动 pyspark</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">PYSPARK_PYTHON=python3 ./</span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">bin</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/pyspark</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Spark 2.1.0 仅支持 Python 2.7+/3.4+的版本。本系列教程统一使用 Python 3.4 以上的版本。在 Ubuntu 16.04 中已经自带了 Python 3.5,就不用再安装 Python.如果你的系统中仍未安装好 Python 3.4 以上的版本，请安装 Python 3.4 以上的版本</p><p>在 pyspark 的交互环境下，输入如下代码</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">fileRDD = sc.textFile(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&#39;hdfs://localhost:9000/test.txt&#39;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">def</span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;"> contains</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">line</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">):</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">... </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">return</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> &#39;hello world&#39;</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> in</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> line</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">filterRDD = fileRDD.filter(contains)</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">filterRDD.cache()</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">filterRDD.count()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>可以看出，一个 Spark 应用程序，基本是基于 RDD 的一系列计算操作。</p><p>第 1 行代码从 HDFS 文件中读取数据创建一个 RDD；</p><p>第 2、3 行定义一个过滤函数;</p><p>第 4 行代码对 fileRDD 进行转换操作得到一个新的 RDD，即 filterRDD；</p><p>第 5 行代码表示对 filterRDD 进行持久化，把它保存在内存或磁盘中（这里采用 cache 接口把数据集保存在内存中），方便后续重复使用.</p><p>当数据被反复访问时（比如查询一些热点数据，或者运行迭代算法），这是非常有用的，而且通过 cache()可以缓存非常大的数据集，支持跨越几十甚至上百个节点；第 5 行代码中的 count()是一个行动操作，用于计算一个 RDD 集合中包含的元素个数。这个程序的执行过程如下：</p><p>*  创建这个 Spark 程序的执行上下文，即创建 SparkContext 对象； *  从外部数据源（即 HDFS 文件）中读取数据创建 fileRDD 对象； *  构建起 fileRDD 和 filterRDD 之间的依赖关系，形成 DAG 图，这时候并没有发生真正的计算，只是记录转换的轨迹； *  执行到第 6 行代码时，count()是一个行动类型的操作，触发真正的计算，开始实际执行从 fileRDD 到 filterRDD 的转换操作，并把结果持久化到内存中，最后计算出 filterRDD 中包含的元素个数。</p><h2 id="_3-rdd-特性" tabindex="-1">3.RDD 特性 <a class="header-anchor" href="#_3-rdd-特性" aria-label="Permalink to “3.RDD 特性”">​</a></h2><p>总体而言，Spark 采用 RDD 以后能够实现高效计算的主要原因如下： （1）高效的容错性。现有的分布式共享内存、键值存储、内存数据库等，为了实现容错，必须在集群节点之间进行数据复制或者记录日志，也就是在节点之间会发生大量的数据传输，这对于数据密集型应用而言会带来很大的开销。在 RDD 的设计中，数据只读，不可修改，如果需要修改数据，必须从父 RDD 转换到子 RDD，由此在不同 RDD 之间建立了血缘关系。所以，RDD 是一种天生具有容错机制的特殊集合，不需要通过数据冗余的方式（比如检查点）实现容错，而只需通过 RDD 父子依赖（血缘）关系重新计算得到丢失的分区来实现容错，无需回滚整个系统，这样就避免了数据复制的高开销，而且重算过程可以在不同节点之间并行进行，实现了高效的容错。此外，RDD 提供的转换操作都是一些粗粒度的操作（比如 map、filter 和 join），RDD 依赖关系只需要记录这种粗粒度的转换操作，而不需要记录具体的数据和各种细粒度操作的日志（比如对哪个数据项进行了修改），这就大大降低了数据密集型应用中的容错开销； （2）中间结果持久化到内存。数据在内存中的多个 RDD 操作之间进行传递，不需要“落地”到磁盘上，避免了不必要的读写磁盘开销； （3）存放的数据可以是 Java 对象，避免了不必要的对象序列化和反序列化开销。</p><h2 id="_4-rdd-之间的依赖关系" tabindex="-1">4. RDD 之间的依赖关系 <a class="header-anchor" href="#_4-rdd-之间的依赖关系" aria-label="Permalink to “4. RDD 之间的依赖关系”">​</a></h2><p>RDD 中不同的操作会使得不同 RDD 中的分区会产生不同的依赖。RDD 中的依赖关系分为窄依赖（Narrow Dependency）与宽依赖（Wide Dependency），图 9-10 展示了两种依赖之间的区别。</p><p>窄依赖表现为一个父 RDD 的分区对应于一个子 RDD 的分区，或多个父 RDD 的分区对应于一个子 RDD 的分区；比如图 9-10(a)中，RDD1 是 RDD2 的父 RDD，RDD2 是子 RDD，RDD1 的分区 1，对应于 RDD2 的一个分区（即分区 4）；再比如，RDD6 和 RDD7 都是 RDD8 的父 RDD，RDD6 中的分区（分区 15）和 RDD7 中的分区（分区 18），两者都对应于 RDD8 中的一个分区（分区 21）。</p><h6 id="宽依赖则表现为存在一个父-rdd-的一个分区对应一个子-rdd-的多个分区。比如图-9-10-b-中-rdd9-是-rdd12-的父-rdd-rdd9-中的分区-24-对应了-rdd12-中的两个分区-即分区-27-和分区-28-。" tabindex="-1">宽依赖则表现为存在一个父 RDD 的一个分区对应一个子 RDD 的多个分区。比如图 9-10(b)中，RDD9 是 RDD12 的父 RDD，RDD9 中的分区 24 对应了 RDD12 中的两个分区（即分区 27 和分区 28）。 <a class="header-anchor" href="#宽依赖则表现为存在一个父-rdd-的一个分区对应一个子-rdd-的多个分区。比如图-9-10-b-中-rdd9-是-rdd12-的父-rdd-rdd9-中的分区-24-对应了-rdd12-中的两个分区-即分区-27-和分区-28-。" aria-label="Permalink to “宽依赖则表现为存在一个父 RDD 的一个分区对应一个子 RDD 的多个分区。比如图 9-10(b)中，RDD9 是 RDD12 的父 RDD，RDD9 中的分区 24 对应了 RDD12 中的两个分区（即分区 27 和分区 28）。”">​</a></h6><p>总体而言，如果父 RDD 的一个分区只被一个子 RDD 的一个分区所使用就是窄依赖，否则就是宽依赖。窄依赖典型的操作包括 map、filter、union 等，宽依赖典型的操作包括 groupByKey、sortByKey 等。对于连接（join）操作，可以分为两种情况。 （1）对输入进行协同划分，属于窄依赖（如图 9-10(a)所示）。所谓协同划分（co-partitioned）是指多个父 RDD 的某一分区的所有“键（key）”，落在子 RDD 的同一个分区内，不会产生同一个父 RDD 的某一分区，落在子 RDD 的两个分区的情况。 （2）对输入做非协同划分，属于宽依赖，如图 9-10(b)所示。 对于窄依赖的 RDD，可以以流水线的方式计算所有父分区，不会造成网络之间的数据混合。对于宽依赖的 RDD，则通常伴随着 Shuffle 操作，即首先需要计算好所有父分区数据，然后在节点之间进行 Shuffle。 <img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-10-%E7%AA%84%E4%BE%9D%E8%B5%96%E4%B8%8E%E5%AE%BD%E4%BE%9D%E8%B5%96%E7%9A%84%E5%8C%BA%E5%88%AB.jpg" alt="图 9-10 窄依赖与宽依赖的区别"> 图 9-10 窄依赖与宽依赖的区别 Spark 的这种依赖关系设计，使其具有了天生的容错性，大大加快了 Spark 的执行速度。因为，RDD 数据集通过“血缘关系”记住了它是如何从其它 RDD 中演变过来的，血缘关系记录的是粗颗粒度的转换操作行为，当这个 RDD 的部分分区数据丢失时，它可以通过血缘关系获取足够的信息来重新运算和恢复丢失的数据分区，由此带来了性能的提升。相对而言，在两种依赖关系中，窄依赖的失败恢复更为高效，它只需要根据父 RDD 分区重新计算丢失的分区即可（不需要重新计算所有分区），而且可以并行地在不同节点进行重新计算。而对于宽依赖而言，单个节点失效通常意味着重新计算过程会涉及多个父 RDD 分区，开销较大。此外，Spark 还提供了数据检查点和记录日志，用于持久化中间 RDD，从而使得在进行失败恢复时不需要追溯到最开始的阶段。在进行故障恢复时，Spark 会对数据检查点开销和重新计算 RDD 分区的开销进行比较，从而自动选择最优的恢复策略。</p><h2 id="_5-阶段的划分" tabindex="-1">5.阶段的划分 <a class="header-anchor" href="#_5-阶段的划分" aria-label="Permalink to “5.阶段的划分”">​</a></h2><p>Spark 通过分析各个 RDD 的依赖关系生成了 DAG，再通过分析各个 RDD 中的分区之间的依赖关系来决定如何划分阶段，具体划分方法是：在 DAG 中进行反向解析，遇到宽依赖就断开，遇到窄依赖就把当前的 RDD 加入到当前的阶段中；将窄依赖尽量划分在同一个阶段中，可以实现流水线计算（具体的阶段划分算法请参见 AMP 实验室发表的论文《Resilient Distributed Datasets: A Fault-Tolerant Abstraction for In-Memory Cluster Computing》）。例如，如图 9-11 所示，假设从 HDFS 中读入数据生成 3 个不同的 RDD（即 A、C 和 E），通过一系列转换操作后再将计算结果保存回 HDFS。对 DAG 进行解析时，在依赖图中进行反向解析，由于从 RDD A 到 RDD B 的转换以及从 RDD B 和 F 到 RDD G 的转换，都属于宽依赖，因此，在宽依赖处断开后可以得到三个阶段，即阶段 1、阶段 2 和阶段 3。可以看出，在阶段 2 中，从 map 到 union 都是窄依赖，这两步操作可以形成一个流水线操作，比如，分区 7 通过 map 操作生成的分区 9，可以不用等待分区 8 到分区 9 这个转换操作的计算结束，而是继续进行 union 操作，转换得到分区 13，这样流水线执行大大提高了计算的效率。 <img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-11-%E6%A0%B9%E6%8D%AERDD%E5%88%86%E5%8C%BA%E7%9A%84%E4%BE%9D%E8%B5%96%E5%85%B3%E7%B3%BB%E5%88%92%E5%88%86%E9%98%B6%E6%AE%B5.jpg" alt="图 9-11 根据 RDD 分区的依赖关系划分阶段"> 图 9-11 根据 RDD 分区的依赖关系划分阶段</p><p>由上述论述可知，把一个 DAG 图划分成多个“阶段”以后，每个阶段都代表了一组关联的、相互之间没有 Shuffle 依赖关系的任务组成的任务集合。每个任务集合会被提交给任务调度器（TaskScheduler）进行处理，由任务调度器将任务分发给 Executor 运行。</p><h2 id="_6-rdd-运行过程" tabindex="-1">6.RDD 运行过程 <a class="header-anchor" href="#_6-rdd-运行过程" aria-label="Permalink to “6.RDD 运行过程”">​</a></h2><p>通过上述对 RDD 概念、依赖关系和阶段划分的介绍，结合之前介绍的 Spark 运行基本流程，这里再总结一下 RDD 在 Spark 架构中的运行过程（如图 9-12 所示）： （1）创建 RDD 对象； （2）SparkContext 负责计算 RDD 之间的依赖关系，构建 DAG； （3）DAGScheduler 负责把 DAG 图分解成多个阶段，每个阶段中包含了多个任务，每个任务会被任务调度器分发给各个工作节点（Worker Node）上的 Executor 去执行。 <img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-12-RDD%E5%9C%A8Spark%E4%B8%AD%E7%9A%84%E8%BF%90%E8%A1%8C%E8%BF%87%E7%A8%8B.jpg" alt="图 9-12 RDD 在 Spark 中的运行过程"> 图 9-12 RDD 在 Spark 中的运行过程</p><h1 id="spark-的部署模式-python-版" tabindex="-1">Spark 的部署模式(Python 版) <a class="header-anchor" href="#spark-的部署模式-python-版" aria-label="Permalink to “Spark 的部署模式(Python 版)”">​</a></h1><p>本节首先介绍 Spark 支持的三种典型集群部署方式，即 standalone、Spark on Mesos 和 Spark on YARN；然后，介绍在企业中是如何具体部署和应用 Spark 框架的，在企业实际应用环境中，针对不同的应用场景，可以采用不同的部署应用方式，或者采用 Spark 完全替代原有的 Hadoop 架构，或者采用 Spark 和 Hadoop 一起部署的方式。</p><h2 id="spark-三种部署方式" tabindex="-1">Spark 三种部署方式 <a class="header-anchor" href="#spark-三种部署方式" aria-label="Permalink to “Spark 三种部署方式”">​</a></h2><p>Spark 应用程序在集群上部署运行时，可以由不同的组件为其提供资源管理调度服务（资源包括 CPU、内存等）。比如，可以使用自带的独立集群管理器（standalone），或者使用 YARN，也可以使用 Mesos。因此，Spark 包括三种不同类型的集群部署方式，包括 standalone、Spark on Mesos 和 Spark on YARN。</p><p>1.standalone 模式与 MapReduce1.0 框架类似，Spark 框架本身也自带了完整的资源调度管理服务，可以独立部署到一个集群中，而不需要依赖其他系统来为其提供资源管理调度服务。在架构的设计上，Spark 与 MapReduce1.0 完全一致，都是由一个 Master 和若干个 Slave 构成，并且以槽（slot）作为资源分配单位。不同的是，Spark 中的槽不再像 MapReduce1.0 那样分为 Map 槽和 Reduce 槽，而是只设计了统一的一种槽提供给各种任务来使用。</p><p>2.Spark on Mesos 模式 Mesos 是一种资源调度管理框架，可以为运行在它上面的 Spark 提供服务。Spark on Mesos 模式中，Spark 程序所需要的各种资源，都由 Mesos 负责调度。由于 Mesos 和 Spark 存在一定的血缘关系，因此，Spark 这个框架在进行设计开发的时候，就充分考虑到了对 Mesos 的充分支持，因此，相对而言，Spark 运行在 Mesos 上，要比运行在 YARN 上更加灵活、自然。目前，Spark 官方推荐采用这种模式，所以，许多公司在实际应用中也采用该模式。</p><p>3.Spark on YARN 模式 Spark 可运行于 YARN 之上，与 Hadoop 进行统一部署，即“Spark on YARN”，其架构如图 9-13 所示，资源管理和调度依赖 YARN，分布式存储则依赖 HDFS</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-13-Spark-on-Yarn%E6%9E%B6%E6%9E%84.jpg" alt="img"> 图 9-13 Spark on YARN 架构</p><h2 id="从-hadoop-storm-架构转向-spark-架构" tabindex="-1">从“Hadoop+Storm”架构转向 Spark 架构 <a class="header-anchor" href="#从-hadoop-storm-架构转向-spark-架构" aria-label="Permalink to “从“Hadoop+Storm”架构转向 Spark 架构”">​</a></h2><p>为了能同时进行批处理与流处理，企业应用中通常会采用“Hadoop+Storm”的架构（也称为 Lambda 架构）。图 9-14 给出了采用“Hadoop+Storm”部署方式的一个案例，在这种部署架构中，Hadoop 和 Storm 框架部署在资源管理框架 YARN（或 Mesos）之上，接受统一的资源管理和调度，并共享底层的数据存储（HDFS、HBase、Cassandra 等）。Hadoop 负责对批量历史数据的实时查询和离线分析，而 Storm 则负责对流数据的实时处理。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-14-%E9%87%87%E7%94%A8HadoopStorm%E9%83%A8%E7%BD%B2%E6%96%B9%E5%BC%8F%E7%9A%84%E4%B8%80%E4%B8%AA%E6%A1%88%E4%BE%8B.jpg" alt="img"></p><p>图 9-14 采用“Hadoop+Storm”部署方式的一个案例</p><p>但是，上面这种架构部署较为繁琐。由于 Spark 同时支持批处理与流处理，因此，对于一些类型的企业应用而言，从“Hadoop+Storm”架构转向 Spark 架构（如图 9-15 所示）就成为一种很自然的选择。采用 Spark 架构具有如下优点： *  实现一键式安装和配置、线程级别的任务监控和告警； *  降低硬件集群、软件维护、任务监控和应用开发的难度； *  便于做成统一的硬件、计算平台资源池。</p><p>需要说明的是，Spark Streaming 的原理是将流数据分解成一系列短小的批处理作业，每个短小的批处理作业使用面向批处理的 Spark Core 进行处理，通过这种方式变相实现流计算，而不是真正实时的流计算，因而通常无法实现毫秒级的响应。因此，对于需要毫秒级实时响应的企业应用而言，仍然需要采用流计算框架（如 Storm）。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-15-%E7%94%A8Spark%E6%9E%B6%E6%9E%84%E6%BB%A1%E8%B6%B3%E6%89%B9%E5%A4%84%E7%90%86%E5%92%8C%E6%B5%81%E5%A4%84%E7%90%86%E9%9C%80%E6%B1%82.jpg" alt="img"> 图 9-15 用 Spark 架构同时满足批处理和流处理需求</p><h2 id="hadoop-和-spark-的统一部署" tabindex="-1">Hadoop 和 Spark 的统一部署 <a class="header-anchor" href="#hadoop-和-spark-的统一部署" aria-label="Permalink to “Hadoop 和 Spark 的统一部署”">​</a></h2><p>一方面，由于 Hadoop 生态系统中的一些组件所实现的功能，目前还是无法由 Spark 取代的，比如，Storm 可以实现毫秒级响应的流计算，但是，Spark 则无法做到毫秒级响应。另一方面，企业中已经有许多现有的应用，都是基于现有的 Hadoop 组件开发的，完全转移到 Spark 上需要一定的成本。因此，在许多企业实际应用中，Hadoop 和 Spark 的统一部署是一种比较现实合理的选择。 由于 Hadoop MapReduce、HBase、Storm 和 Spark 等，都可以运行在资源管理框架 YARN 之上，因此，可以在 YARN 之上进行统一部署（如图 9-16 所示）。这些不同的计算框架统一运行在 YARN 中，可以带来如下好处： *  计算资源按需伸缩； *  不用负载应用混搭，集群利用率高； *  共享底层存储，避免数据跨集群迁移。</p><p><img src="http://dblab.xmu.edu.cn/blog/wp-content/uploads/2016/11/%E5%9B%BE9-16-Hadoop%E5%92%8CSpark%E7%9A%84%E7%BB%9F%E4%B8%80%E9%83%A8%E7%BD%B2.jpg" alt="img"> 图 9-16 Hadoop 和 Spark 的统一部署</p>`,78)])])}const S=p(o,[["render",i]]);export{h as __pageData,S as default};
